export function searchBoericke(query: string): BoerickeRemedy[] {
  const q = query.toLowerCase().trim();
  if (!q) return BOERICKE_MM;
  return BOERICKE_MM.filter(r =>
    r.name.toLowerCase().includes(q) ||
    r.abbrev.toLowerCase().includes(q) ||
    r.intro.toLowerCase().includes(q) ||
    r.keynotes.some(k => k.toLowerCase().includes(q))
  );
}